+   * Save database to persistent storage
+   * - Browser: IndexedDB
+   * - Node.js: File system
+   */
+  async save(path?: string): Promise<void> {
+    if (!this.db) {
+      throw new Error('Database not initialized. Call init() first.');
+    }
+
+    if (isBrowser) {
